// Parse scores and check for alerts
const results = $input.all();
const alerts = [];
const summaryRows = [];

for (const result of results) {
  const parsed = typeof result.json.parsed_content === 'string' 
    ? JSON.parse(result.json.parsed_content) 
    : result.json.parsed_content;

  summaryRows.push({
    client: result.json.client_name,
    score: parsed.health_score,
    trend: parsed.trend,
    top_risk: (parsed.risk_flags || [])[0] || 'None'
  });

  if (parsed.health_score < 55) {
    alerts.push({ client: result.json.client_name, score: parsed.health_score, actions: parsed.recommended_actions });
  }
}

const digestHtml = `<h2>Weekly Client Health Digest</h2>
<table border='1' cellpadding='5'>
<tr><th>Client</th><th>Score</th><th>Trend</th><th>Top Risk</th></tr>
${summaryRows.map(r => `<tr><td>${r.client}</td><td>${r.score}</td><td>${r.trend}</td><td>${typeof r.top_risk === 'object' ? r.top_risk.description || JSON.stringify(r.top_risk) : r.top_risk}</td></tr>`).join('')}
</table>`;

return [{ json: { digestHtml, alerts, hasAlerts: alerts.length > 0 } }];
